// // This module is designed to handle SD card read and write operations. It has an input 'cmd' to specify the operation (0 for read, 1 for write), an 8-bit 'data_in' for input data during write operations, and an 8-bit 'data_out' for output data during read operations. The controller operates on a clock signal 'clk' and a reset signal 'rst'. Upon reset, the output data is cleared. During a write operation, the input data is stored in an internal register, and during a read operation, the output data is set to the value of that register.
module sd_card_controller(  
    input wire clk,  
    input wire rst,  
    input wire cmd,  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
    reg [7:0] internal_reg;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            internal_reg <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (cmd == 1'b1) begin  // Write operation  
                internal_reg <= data_in;  
            end else begin  // Read operation  
                data_out <= internal_reg;  
            end  
        end  
    end  
endmodule
